import React, { Suspense } from 'react';

// 1. Define the lazy component
const HeavyChart = React.lazy(() => import('./HeavyChart'));

function App() {
  return (
    <div>
      <h1>My Dashboard</h1>
      {/* 2. Wrap in Suspense with a fallback */}
      <Suspense fallback={<div>Loading Chart...</div>}>
        <HeavyChart />
      </Suspense>
    </div>
  );
}

